          console.error(`Error in event handler for ${event}:`, error);
        }
      });
    }
  }
}

class PubSub {
  constructor() {
    this.subscribers = {};
  }
  subscribe(topic, callback) {
    if (!this.subscribers[topic]) {
      this.subscribers[topic] = new Set();
    }
    this.subscribers[topic].add(callback);
    return () => this.subscribers[topic].delete(callback);
  }
  publish(topic, data) {
    const callbacks = this.subscribers[topic];
    if (callbacks) {
      callbacks.forEach(callback => callback(data));
    }
  }
  unsubscribe(topic, callback) {
    this.subscribers[topic]?.delete(callback);
  }
}

const createImmer = (producer) => {
  return (state) => {
    const draft = JSON.parse(JSON.stringify(state));
    producer(draft);
    return draft;
  };
};

const nextState = createImmer((state) => {
  state.users.push({ id: 3, name: 'Bob' });
  state.count += 1;
})(previousState);

const createReducer = (initialState, handlers) => {
  return (state = initialState, action) => {
    const handler = handlers[action.type];
    return handler ? handler(state, action) : state;
  };
};

const reducer = createReducer(
  { count: 0 },
  {
    INCREMENT: (state, action) => ({ ...state, count: state.count + 1 }),
    DECREMENT: (state, action) => ({ ...state, count: state.count - 1 }),
    RESET: () => ({ count: 0 })
  }
);

class CommandManager {
  constructor() {
    this.history = [];
    this.undone = [];
  }
  execute(command) {
    command.execute();
    this.history.push(command);
    this.undone = [];
  }
  undo() {
    const command = this.history.pop();
    if (command) {
      command.undo();
      this.undone.push(command);
    }
  }
  redo() {
    const command = this.undone.pop();
    if (command) {
      command.execute();
      this.history.push(command);
    }
  }
}

class Strategy {
  constructor() {
    this.strategies = {};
  }
  register(name, strategy) {
    this.strategies[name] = strategy;
  }
  execute(name, ...args) {
    const strategy = this.strategies[name];
    if (!strategy) throw new Error(`Strategy ${name} not found`);
    return strategy(...args);
  }
}

class Mediator {
  constructor() {
    this.components = new Map();
  }
  register(name, component) {
    component.setMediator(this);
    this.components.set(name, component);
  }
  notify(sender, event, data) {
    this.components.forEach((component, name) => {
      if (name !== sender) {
        component.handle(event, data);
      }
    });
  }
}
